interface ProductImageProps {
  src: string;
  alt: string;
  category: ProductCategory;
  className?: string;
}

export function ProductImage({ src, alt, category, className = '' }: ProductImageProps) {
  const [hasError, setHasError] = useState(false);

  // Toon placeholder als het een generieke profielafbeelding is of als laden mislukt
  const isGenericProfileImage =
    src.includes('raamprofiel') ||
    src.includes('crepi-isolatie') ||
    src.includes('steenstrips-isolatie') ||
    src.includes('voordeur.png');

  if (hasError || isGenericProfileImage) {
    const placeholder = CATEGORY_PLACEHOLDERS[category] ?? CATEGORY_PLACEHOLDERS.default;
    return (
      <div className={`flex items-center justify-center w-full h-full bg-gradient-to-br from-slate-100 via-white to-sky-50 ${className}`}>
        {placeholder}
      </div>
    );
  }

  return (
    <Image
      src={src}
      alt={alt}
      fill
      sizes="(max-width: 768px) 100vw, (max-width: 1280px) 50vw, 33vw"
      className={`object-contain p-6 transition duration-500 group-hover:scale-105 ${className}`}
      onError={() => setHasError(true)}
    />
  );
}
